"""
MABE Bootstrap: Red Problem Analysis
Run: python bootstrap_red_problem.py
"""
import base64, pathlib

FILES = {
    "optical/red_problem.py": "",
    "tests/test_optical/test_red_problem.py": "",
}

def main():
    print()
    print("  MABE Red Problem Analysis Bootstrap")
    print("  " + "=" * 38)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  Created: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python -m pytest tests/test_optical/test_red_problem.py -v")
    print()

if __name__ == "__main__":
    main()